const items = $input.all();
const outputs = [];

for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  const keys = Object.keys(bin);

  if (!keys.length) {
    outputs.push({ json: { key: '', fileName: '', mimeType: '', url: '' } });
    continue;
  }

  for (const key of keys) {
    const meta = bin[key] || {};
    let url = '';
    try {
      const buf = await this.helpers.getBinaryDataBuffer(i, key);
      const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
      const base64 = Buffer.isBuffer(buf) ? buf.toString('base64') : Buffer.from(buf).toString('base64');
      url = base64 ? `data:${mime};base64,${base64}` : '';
    } catch (_) {
      const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
      const data = meta.data;
      if (typeof data === 'string' && data.length) url = `data:${mime};base64,${data}`;
    }

    outputs.push({
      json: {
        key,
        fileName: meta.fileName || meta.filename || key,
        mimeType: meta.mimeType || meta.mimetype || '',
        url
      }
    });
  }
}

return outputs.length ? outputs : [{ json: { key: '', fileName: '', mimeType: '', url: '' } }];

// ================================================
// n8n Code 节点专用代码
// 功能：将上游所有数据原样传递，并为每个item添加图片数量统计
// 返回：所有输入项，每个项的JSON中都增加了imageCount字段
// ================================================

// 遍历输入的所有 items
for (const item of $input.all()) {
  // 动态计算当前 item 的 binary 中包含多少张图片
  // 如果 item.binary 不存在，则其键的数量为 0
  const calculatedImageCount = item.binary ? Object.keys(item.binary).length : 0;

  // 将计算出的图片数量更新到 item 的 json 部分
  item.json.imageCount = calculatedImageCount;

  // 可选：打印日志信息用于调试
  console.log(`Item ${item.json.image_key || 'unknown'} has ${calculatedImageCount} image(s) in its binary data.`);
}

// 返回所有经过处理的输入项
return $input.all();

