// 别忘了把最后一段加上
if (currentDesc) mergedDescriptions.push(currentDesc);

// 5. 从 Edit Fields 节点提取 cpimage 和 ckimage 开头的 binary
let editFieldsImageCount = 0;
let editFieldsConnected = false;

try {
  let editFieldsNode;
  try { editFieldsNode = $('Edit Fields'); } catch(e) {}
  try { if (!editFieldsNode) editFieldsNode = $('Edit_Fields'); } catch(e) {}
  try { if (!editFieldsNode) editFieldsNode = $('edit-fields'); } catch(e) {}
  try { if (!editFieldsNode) editFieldsNode = $('Edit Fields2'); } catch(e) {}

  const editFieldsOutput = editFieldsNode ? editFieldsNode.all() : [];

  for (const item of editFieldsOutput) {
    if (!item?.binary) continue;

    for (const key in item.binary) {
      // 修改点：同时匹配 cpimage 和 ckimage 开头
      if (key.startsWith('cpimage') || key.startsWith('ckimage')) {
        const newKey = `${++index}图`;
        images[newKey] = {
          ...item.binary[key],
          sourceNode: 'Edit Fields',
          sourceField: key
        };
        editFieldsImageCount++;
      }
    }
  }

  editFieldsConnected = editFieldsImageCount > 0;
} catch (err) {
  console.error("Edit Fields node error:", err.message);
}

// 6. 将描述与图片进行匹配
// 使用 mergedDescriptions 数组，确保描述是合并后的完整版本
const descriptions = {};
mergedDescriptions.forEach((desc, i) => {
  const num = i + 1;
  const key = `${num}图`;
  descriptions[key] = desc;
});

// 7. 验证并输出
const descCount = Object.keys(descriptions).length;
const imgCount = Object.keys(images).length;

// 调试信息
console.log('Descriptions:', descriptions);
console.log('Images keys:', Object.keys(images));

return [{
  json: {
    descriptions,
    images: Object.keys(images),
    imageCount: imgCount,
    descriptionCount: descCount,
    inputImageCount: index - editFieldsImageCount,
    editFieldsImageCount,
    editFieldsConnected,
    matchedPairs: Object.keys(descriptions).filter(k => images[k]).length
  },
  binary: images
}];

// 获取所有输入数据
const allItems = $input.all();

// 假设所有的图片都在第一个输入 Item 中（通常 n8n 会把 binary 放在第一个 item 或均匀分布）
// 我们先提取出所有的 binary 数据
const allBinaries = {};
allItems.forEach(item => {
  if (item.binary) {
    Object.assign(allBinaries, item.binary);
  }
});

let results = [];

// 遍历输入，提取 descriptions 下的所有图
// 假设 descriptions 在第一个 Item 的 json 中
const descriptions = allItems[0].json.descriptions;

for (const key in descriptions) {
  results.push({
    json: {
      image_key: key,            // 对应 "1图", "2图" 等
      prompt: descriptions[key]  // 对应具体的描述文本
    },
    // 将之前收集到的所有二进制数据完整复制给每一个 item
    binary: { ...allBinaries } 
  });
}

return results;

// 同时提取 ckimage 和 cpimage 开头的 binary
// 只有两个前缀都存在图片时，才提取；否则不提取（binary 返回空）

const binary = $input.item.binary || {};

const hasCkimage = Object.keys(binary).some(key => key.startsWith('ckimage'));
const hasCpimage = Object.keys(binary).some(key => key.startsWith('cpimage'));

// 只有两个前缀都存在，才进行提取
if (!hasCkimage || !hasCpimage) {
  console.log('缺少 ckimage 或 cpimage 前缀的图片，不进行提取');
  return [{
    json: {
      message: "缺少 ckimage 或 cpimage 前缀的图片，不提取 binary",
      hasCkimage: hasCkimage,
      hasCpimage: hasCpimage,
      extracted: false
    },
    binary: {}   // 不返回任何 binary
  }];
}

// 两个前缀都存在，开始提取并重命名
const extractedBinary = {};

let index = 1;

// 提取 ckimage 开头的
Object.keys(binary).forEach(key => {
  if (key.startsWith('ckimage')) {
    extractedBinary[`ckimage_${index}`] = { ...binary[key] };
    index++;
  }
});

// 提取 cpimage 开头的（继续编号）
Object.keys(binary).forEach(key => {
  if (key.startsWith('cpimage')) {
    extractedBinary[`cpimage_${index}`] = { ...binary[key] };
    index++;
  }
});

console.log(`成功提取 ckimage 和 cpimage 图片，共 ${index - 1} 张`);

return [{
  json: {
    message: "成功提取 ckimage 和 cpimage 的图片",
    ckimageCount: Object.keys(binary).filter(k => k.startsWith('ckimage')).length,
    cpimageCount: Object.keys(binary).filter(k => k.startsWith('cpimage')).length,
    extracted: true
  },
  binary: extractedBinary
}];
